'use client';
import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import {
    Palette, Globe, Image as ImageIcon, Save, CheckCircle,
    ImagePlus, Link2, Loader2, ExternalLink, Eye, RefreshCw
} from 'lucide-react';

export default function BrandingPage() {
    const router = useRouter();
    const [tenant, setTenant] = useState(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [saved, setSaved] = useState(false);
    const [error, setError] = useState('');

    const [form, setForm] = useState({
        name: '', tagline: '', description: '',
        phone: '', address: '',
        primaryColor: '#10B981',
        logoInitials: '', logoUrl: '', heroImage: '',
    });

    const load = useCallback(async () => {
        setLoading(true);
        setError('');
        try {
            const meRes = await fetch('/api/auth/me');
            if (!meRes.ok) { router.replace('/login'); return; }
            const { user } = await meRes.json();
            if (!user.tenantId) { setError('Super admin accounts do not have a public hospital page.'); setLoading(false); return; }
            const tRes = await fetch(`/api/tenants/${user.tenantId}`);
            if (!tRes.ok) throw new Error('Could not load tenant');
            const { tenant: t } = await tRes.json();
            setTenant(t);
            setForm({
                name: t.name || '',
                tagline: t.tagline || '',
                description: t.description || '',
                phone: t.phone || '',
                address: t.address || '',
                primaryColor: t.primaryColor || '#10B981',
                logoInitials: t.logoInitials || '',
                logoUrl: t.logoUrl || '',
                heroImage: t.heroImage || '',
            });
        } catch (e) {
            setError('Could not load branding settings.');
        } finally {
            setLoading(false);
        }
    }, [router]);

    useEffect(() => { load(); }, [load]);

    const handleSave = async () => {
        if (!tenant) return;
        setSaving(true); setSaved(false); setError('');
        try {
            const res = await fetch(`/api/tenants/${tenant.id}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(form),
            });
            if (!res.ok) throw new Error((await res.json()).error || 'Save failed');
            setSaved(true);
            setTimeout(() => setSaved(false), 3500);
        } catch (e) {
            setError(e.message);
        } finally {
            setSaving(false);
        }
    };

    const accent = form.primaryColor || '#10B981';

    if (loading) return (
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '80px', gap: '12px', color: '#94A3B8', fontSize: '14px' }}>
            <Loader2 size={20} style={{ animation: 'spin 1s linear infinite' }} />
            Loading branding settings…
            <style>{`@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}`}</style>
        </div>
    );

    const inputStyle = { width: '100%', padding: '10px 14px', border: '1px solid #E2E8F0', borderRadius: '8px', fontSize: '14px', outline: 'none', background: '#FFFFFF', boxSizing: 'border-box', fontFamily: 'inherit' };
    const Field = ({ label, hint, children, full }) => (
        <div style={{ gridColumn: full ? '1/-1' : 'auto', marginBottom: '4px' }}>
            <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#334155', marginBottom: hint ? '4px' : '7px' }}>{label}</label>
            {hint && <p style={{ fontSize: '12px', color: '#94A3B8', margin: '0 0 8px' }}>{hint}</p>}
            {children}
        </div>
    );

    return (
        <div className="fade-in" style={{ maxWidth: '920px' }}>
            <style>{`@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}`}</style>

            {/* Header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '28px', gap: '16px', flexWrap: 'wrap' }}>
                <div>
                    <h1 style={{ fontSize: '24px', fontWeight: 700, color: '#0F172A', marginBottom: '6px', letterSpacing: '-0.02em' }}>Website Branding</h1>
                    <p style={{ fontSize: '14px', color: '#64748B', margin: 0 }}>Configure your public hospital website — hero, logo, colour, and contact details.</p>
                </div>
                <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                    {tenant && (
                        <a href={`/${tenant.slug}`} target="_blank" rel="noreferrer"
                            style={{ display: 'inline-flex', alignItems: 'center', gap: '7px', padding: '10px 16px', background: '#FFFFFF', border: '1px solid #E2E8F0', borderRadius: '8px', fontSize: '14px', fontWeight: 600, color: '#475569', textDecoration: 'none' }}>
                            <Eye size={14} /> Preview Site
                        </a>
                    )}
                    <button onClick={handleSave} disabled={saving}
                        style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', padding: '10px 22px', background: saved ? '#10B981' : accent, color: '#fff', border: 'none', borderRadius: '8px', fontSize: '14px', fontWeight: 700, cursor: saving ? 'not-allowed' : 'pointer', boxShadow: `0 4px 14px ${accent}40`, transition: 'background 0.2s' }}>
                        {saving ? <Loader2 size={15} style={{ animation: 'spin 1s linear infinite' }} /> : saved ? <CheckCircle size={15} /> : <Save size={15} />}
                        {saving ? 'Saving…' : saved ? 'Saved!' : 'Save Changes'}
                    </button>
                </div>
            </div>

            {error && (
                <div style={{ background: '#FEF2F2', border: '1px solid #FECACA', borderRadius: '10px', padding: '12px 16px', marginBottom: '20px', color: '#DC2626', fontSize: '14px' }}>{error}</div>
            )}
            {saved && (
                <div style={{ background: '#ECFDF5', border: '1px solid #A7F3D0', borderRadius: '10px', padding: '12px 16px', marginBottom: '20px', color: '#065F46', fontSize: '14px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <CheckCircle size={16} /> Changes saved! Your public website will reflect the updates shortly.
                </div>
            )}

            <div style={{ display: 'grid', gap: '20px' }}>

                {/* ── General Info Card ── */}
                <div style={{ background: '#FFFFFF', border: '1px solid #E2E8F0', borderRadius: '16px', overflow: 'hidden' }}>
                    <div style={{ padding: '18px 24px', borderBottom: '1px solid #E2E8F0', display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <div style={{ width: '32px', height: '32px', borderRadius: '9px', background: `${accent}15`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            <Globe size={16} style={{ color: accent }} />
                        </div>
                        <div>
                            <h2 style={{ margin: 0, fontSize: '15px', fontWeight: 700, color: '#0F172A' }}>Hospital Information</h2>
                            <p style={{ margin: 0, fontSize: '12px', color: '#94A3B8' }}>Shown on your public website, invoices, and reports.</p>
                        </div>
                    </div>
                    <div style={{ padding: '24px', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px 28px' }}>
                        <Field label="Hospital Name">
                            <input style={inputStyle} type="text" value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="Apollo Health Systems" />
                        </Field>
                        <Field label="Phone / Helpline">
                            <input style={inputStyle} type="tel" value={form.phone} onChange={e => setForm(f => ({ ...f, phone: e.target.value }))} placeholder="+91 98765 43210" />
                        </Field>
                        <Field label="Tagline" hint="Shown as the main headline in the hero section">
                            <input style={inputStyle} type="text" value={form.tagline} onChange={e => setForm(f => ({ ...f, tagline: e.target.value }))} placeholder="Your Health, Our Priority" />
                        </Field>
                        <Field label="Admin Email (read-only)">
                            <input style={{ ...inputStyle, background: '#F8FAFC', color: '#94A3B8' }} type="email" value={tenant?.adminEmail || ''} disabled />
                        </Field>
                        <Field label="Address / Location" full>
                            <input style={inputStyle} type="text" value={form.address} onChange={e => setForm(f => ({ ...f, address: e.target.value }))} placeholder="123 Medical Lane, Mumbai, Maharashtra - 400001" />
                        </Field>
                        <Field label="About Your Hospital" hint="Shown in the hero section and footer (2–3 sentences)" full>
                            <textarea rows={3} value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))}
                                placeholder="Describe your hospital — specialities, experience, accreditations…"
                                style={{ ...inputStyle, resize: 'vertical' }} />
                        </Field>
                    </div>
                </div>

                {/* ── Branding Card ── */}
                <div style={{ background: '#FFFFFF', border: '1px solid #E2E8F0', borderRadius: '16px', overflow: 'hidden' }}>
                    <div style={{ padding: '18px 24px', borderBottom: '1px solid #E2E8F0', display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <div style={{ width: '32px', height: '32px', borderRadius: '9px', background: `${accent}15`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            <Palette size={16} style={{ color: accent }} />
                        </div>
                        <div>
                            <h2 style={{ margin: 0, fontSize: '15px', fontWeight: 700, color: '#0F172A' }}>Colours & Logo</h2>
                            <p style={{ margin: 0, fontSize: '12px', color: '#94A3B8' }}>Brand colour is applied site-wide automatically.</p>
                        </div>
                    </div>
                    <div style={{ padding: '24px', display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '20px 28px' }}>
                        <Field label="Brand / Primary Colour">
                            <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                                <input type="color" value={form.primaryColor} onChange={e => setForm(f => ({ ...f, primaryColor: e.target.value }))}
                                    style={{ width: '46px', height: '42px', border: '1px solid #E2E8F0', borderRadius: '8px', cursor: 'pointer', padding: '3px', boxSizing: 'border-box' }} />
                                <input type="text" value={form.primaryColor} onChange={e => setForm(f => ({ ...f, primaryColor: e.target.value }))}
                                    style={{ flex: 1, padding: '10px 12px', border: '1px solid #E2E8F0', borderRadius: '8px', fontSize: '14px', fontFamily: 'monospace', outline: 'none', letterSpacing: '0.04em' }} />
                            </div>
                        </Field>
                        <Field label="Logo Initials" hint="Fallback when no logo URL is provided">
                            <input type="text" value={form.logoInitials} maxLength={3} onChange={e => setForm(f => ({ ...f, logoInitials: e.target.value.toUpperCase() }))}
                                style={{ ...inputStyle, letterSpacing: '0.1em', fontWeight: 800, textTransform: 'uppercase', textAlign: 'center', fontSize: '16px' }}
                                placeholder="AH" />
                        </Field>
                        <Field label="Live Preview">
                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '10px 14px', border: '1px solid #E2E8F0', borderRadius: '8px', background: '#F8FAFC', minHeight: '44px' }}>
                                {form.logoUrl ? (
                                    <img src={form.logoUrl} alt="logo" style={{ height: '32px', width: 'auto', maxWidth: '90px', objectFit: 'contain', borderRadius: '4px' }} onError={e => e.currentTarget.style.display = 'none'} />
                                ) : (
                                    <div style={{ width: '34px', height: '34px', borderRadius: '9px', background: `linear-gradient(135deg, ${accent}, ${accent}cc)`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, boxShadow: `0 3px 10px ${accent}40` }}>
                                        <span style={{ color: '#fff', fontWeight: 900, fontSize: '11px' }}>{form.logoInitials || form.name?.substring(0, 2).toUpperCase() || 'NH'}</span>
                                    </div>
                                )}
                                <div>
                                    <span style={{ fontSize: '13px', fontWeight: 700, color: '#0F172A', display: 'block', lineHeight: 1.2 }}>{form.name || 'Hospital Name'}</span>
                                    <span style={{ fontSize: '10px', color: '#94A3B8' }}>Powered by Nexora Health</span>
                                </div>
                            </div>
                        </Field>
                    </div>
                </div>

                {/* ── Images Card ── */}
                <div style={{ background: '#FFFFFF', border: '1px solid #E2E8F0', borderRadius: '16px', overflow: 'hidden' }}>
                    <div style={{ padding: '18px 24px', borderBottom: '1px solid #E2E8F0', display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <div style={{ width: '32px', height: '32px', borderRadius: '9px', background: `${accent}15`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            <ImageIcon size={16} style={{ color: accent }} />
                        </div>
                        <div>
                            <h2 style={{ margin: 0, fontSize: '15px', fontWeight: 700, color: '#0F172A' }}>Images & Media</h2>
                            <p style={{ margin: 0, fontSize: '12px', color: '#94A3B8' }}>Paste public image URLs — no file upload needed.</p>
                        </div>
                    </div>
                    <div style={{ padding: '24px', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '28px' }}>
                        {/* Logo URL */}
                        <div>
                            <Field label="Logo Image URL" hint="Direct URL to PNG, SVG, or WebP. Leave empty to use initials placeholder.">
                                <div style={{ display: 'flex', gap: '8px' }}>
                                    <div style={{ position: 'relative', flex: 1 }}>
                                        <Link2 size={14} style={{ position: 'absolute', left: '12px', top: '12px', color: '#94A3B8' }} />
                                        <input type="url" value={form.logoUrl} onChange={e => setForm(f => ({ ...f, logoUrl: e.target.value }))}
                                            placeholder="https://example.com/logo.png"
                                            style={{ ...inputStyle, paddingLeft: '36px' }} />
                                    </div>
                                    {form.logoUrl && (
                                        <a href={form.logoUrl} target="_blank" rel="noreferrer"
                                            style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', width: '42px', background: '#F8FAFC', border: '1px solid #E2E8F0', borderRadius: '8px', color: '#64748B', flexShrink: 0, textDecoration: 'none' }}>
                                            <ExternalLink size={14} />
                                        </a>
                                    )}
                                </div>
                            </Field>
                            <div style={{ border: '2px dashed #E2E8F0', borderRadius: '12px', minHeight: '100px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#FAFAFA', marginTop: '4px' }}>
                                {form.logoUrl ? (
                                    <img src={form.logoUrl} alt="Logo preview" style={{ maxHeight: '72px', maxWidth: '200px', objectFit: 'contain', borderRadius: '6px' }}
                                        onError={e => e.currentTarget.parentElement.innerHTML = '<p style="font-size:12px;color:#94A3B8;text-align:center;padding:16px;">⚠️ Could not load image. Check the URL.</p>'} />
                                ) : (
                                    <div style={{ textAlign: 'center', padding: '16px' }}>
                                        <ImagePlus size={22} style={{ color: '#CBD5E1', marginBottom: '8px' }} />
                                        <p style={{ fontSize: '12px', color: '#94A3B8', margin: 0 }}>Paste a logo URL above</p>
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Hero Image URL */}
                        <div>
                            <Field label="Hero Background Image URL" hint="Landscape image, 1920×1080 recommended. If empty, a gradient is used automatically.">
                                <div style={{ display: 'flex', gap: '8px' }}>
                                    <div style={{ position: 'relative', flex: 1 }}>
                                        <Link2 size={14} style={{ position: 'absolute', left: '12px', top: '12px', color: '#94A3B8' }} />
                                        <input type="url" value={form.heroImage} onChange={e => setForm(f => ({ ...f, heroImage: e.target.value }))}
                                            placeholder="https://example.com/hospital-hero.jpg"
                                            style={{ ...inputStyle, paddingLeft: '36px' }} />
                                    </div>
                                    {form.heroImage && (
                                        <a href={form.heroImage} target="_blank" rel="noreferrer"
                                            style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', width: '42px', background: '#F8FAFC', border: '1px solid #E2E8F0', borderRadius: '8px', color: '#64748B', flexShrink: 0, textDecoration: 'none' }}>
                                            <ExternalLink size={14} />
                                        </a>
                                    )}
                                </div>
                            </Field>
                            <div style={{ border: '2px dashed #E2E8F0', borderRadius: '12px', overflow: 'hidden', minHeight: '100px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#FAFAFA', marginTop: '4px' }}>
                                {form.heroImage ? (
                                    <img src={form.heroImage} alt="Hero preview" style={{ width: '100%', height: '130px', objectFit: 'cover' }}
                                        onError={e => e.currentTarget.parentElement.innerHTML = '<p style="font-size:12px;color:#94A3B8;text-align:center;padding:16px;">⚠️ Could not load image. Check the URL.</p>'} />
                                ) : (
                                    <div style={{ textAlign: 'center', padding: '16px' }}>
                                        <ImagePlus size={22} style={{ color: '#CBD5E1', marginBottom: '8px' }} />
                                        <p style={{ fontSize: '12px', color: '#94A3B8', margin: 0 }}>Paste a hero image URL above</p>
                                        <p style={{ fontSize: '11px', color: '#CBD5E1', margin: '4px 0 0' }}>Gradient is shown if empty</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                    {/* Tips */}
                    <div style={{ margin: '0 24px 24px', background: `${accent}08`, border: `1px solid ${accent}20`, borderRadius: '10px', padding: '14px 18px' }}>
                        <p style={{ fontSize: '12.5px', color: '#475569', margin: 0, lineHeight: 1.7 }}>
                            <strong>💡 Free image hosting:</strong>{' '}
                            Upload your image to <a href="https://imgbb.com" target="_blank" rel="noreferrer" style={{ color: accent, fontWeight: 600 }}>imgbb.com</a> or{' '}
                            <a href="https://cloudinary.com" target="_blank" rel="noreferrer" style={{ color: accent, fontWeight: 600 }}>Cloudinary</a> (free tier),
                            then paste the <strong>direct image URL</strong> here. For logos, use a transparent PNG or SVG for best results.
                        </p>
                    </div>
                </div>

                {/* Bottom Save */}
                <div style={{ display: 'flex', justifyContent: 'flex-end', paddingBottom: '24px', gap: '12px' }}>
                    <button onClick={load}
                        style={{ display: 'inline-flex', alignItems: 'center', gap: '7px', padding: '11px 18px', background: '#FFFFFF', border: '1px solid #E2E8F0', borderRadius: '8px', fontSize: '14px', fontWeight: 600, color: '#475569', cursor: 'pointer' }}>
                        <RefreshCw size={14} /> Discard Changes
                    </button>
                    <button onClick={handleSave} disabled={saving}
                        style={{ display: 'inline-flex', alignItems: 'center', gap: '8px', padding: '12px 28px', background: saved ? '#10B981' : accent, color: '#fff', border: 'none', borderRadius: '8px', fontSize: '15px', fontWeight: 700, cursor: saving ? 'not-allowed' : 'pointer', boxShadow: `0 4px 14px ${accent}40` }}>
                        {saving ? <Loader2 size={16} style={{ animation: 'spin 1s linear infinite' }} /> : saved ? <CheckCircle size={16} /> : <Save size={16} />}
                        {saving ? 'Saving…' : saved ? 'Saved Successfully!' : 'Save All Changes'}
                    </button>
                </div>
            </div>
        </div>
    );
}

'use client';
import { ArrowLeft, UserCog, Search, Filter, Mail, Phone, MoreVertical, Plus } from 'lucide-react';
import Link from 'next/link';

import { useState, useEffect } from 'react';

export default function DoctorsDirectoryPage() {
    const [doctors, setDoctors] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        const fetchDoctors = async () => {
            try {
                const res = await fetch('/api/hr/staff');
                if (res.ok) {
                    const data = await res.json();
                    // filter to show only doctors
                    const docs = (data.staff || []).filter(s =>
                        s.role === 'doctor' ||
                        (s.department && s.department.toLowerCase().includes('doctor')) ||
                        (s.specialization && s.specialization.length > 0)
                    );
                    setDoctors(docs);
                }
            } catch (err) {
                console.error("Failed to fetch doctors:", err);
            } finally {
                setLoading(false);
            }
        };
        fetchDoctors();
    }, []);

    const filteredDoctors = doctors.filter(doc =>
        (doc.name && doc.name.toLowerCase().includes(searchTerm.toLowerCase())) ||
        (doc.department && doc.department.toLowerCase().includes(searchTerm.toLowerCase())) ||
        (doc.specialization && doc.specialization.toLowerCase().includes(searchTerm.toLowerCase()))
    );

    return (
        <div className="fade-in">
            <div className="dashboard-header-row">
                <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                    <Link href="/hr" className="btn btn-secondary btn-sm" style={{ padding: '8px', border: 'none', background: '#FFFFFF', boxShadow: '0 1px 2px rgba(0,0,0,0.05)' }}>
                        <ArrowLeft size={18} />
                    </Link>
                    <div>
                        <h1 className="page-header__title" style={{ marginBottom: '4px' }}>Medical Staff Directory</h1>
                        <p className="page-header__subtitle">Manage doctors, surgeons, and consulting physicians.</p>
                    </div>
                </div>
                <div className="dashboard-header-buttons">
                    <Link href="/hr/new" className="btn btn-primary btn-sm" style={{ textDecoration: 'none' }}>
                        <Plus size={15} strokeWidth={1.5} />
                        Add Doctor
                    </Link>
                </div>
            </div>

            <div className="card" style={{ padding: '24px' }}>
                <div style={{ display: 'flex', gap: '12px', marginBottom: '24px', flexWrap: 'wrap', alignItems: 'center', justifyContent: 'space-between' }}>
                    <div style={{ display: 'flex', gap: '12px', flex: 1, minWidth: '300px' }}>
                        <div style={{ flex: 1, position: 'relative' }}>
                            <Search size={16} color="#94A3B8" style={{ position: 'absolute', left: '16px', top: '12px' }} />
                            <input type="text" placeholder="Search by name, department, or specialization..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} style={{ width: '100%', padding: '12px 16px 12px 42px', border: '1px solid var(--color-border-light)', borderRadius: '8px', outline: 'none', fontSize: '14px' }} />
                        </div>
                        <button className="btn btn-secondary" style={{ background: '#fff' }}>
                            <Filter size={16} /> Filters
                        </button>
                    </div>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px' }}>
                    {loading ? (
                        <div style={{ padding: '40px', textAlign: 'center', gridColumn: '1 / -1', color: '#94A3B8' }}>Loading doctors mapping...</div>
                    ) : filteredDoctors.length === 0 ? (
                        <div style={{ padding: '40px', textAlign: 'center', gridColumn: '1 / -1', color: '#94A3B8' }}>No medical staff found matching "{searchTerm}"</div>
                    ) : filteredDoctors.map((doc, i) => (
                        <div key={doc.id || i} style={{ border: '1px solid var(--color-border-light)', borderRadius: '12px', padding: '20px', display: 'flex', flexDirection: 'column', gap: '16px', background: '#FFFFFF', transition: 'all 0.2s', cursor: 'default' }} onMouseOver={(e) => { e.currentTarget.style.borderColor = 'var(--color-cyan)'; e.currentTarget.style.boxShadow = '0 4px 12px rgba(0,0,0,0.05)' }} onMouseOut={(e) => { e.currentTarget.style.borderColor = 'var(--color-border-light)'; e.currentTarget.style.boxShadow = 'none' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                                <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
                                    <div style={{ width: '48px', height: '48px', borderRadius: '50%', background: 'rgba(0,194,255,0.1)', color: 'var(--color-cyan)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '18px', fontWeight: 600 }}>
                                        {doc.name ? doc.name.split(' ')[0][0] + (doc.name.split(' ')[1] ? doc.name.split(' ')[1][0] : '') : 'Dr'}
                                    </div>
                                    <div>
                                        <h3 style={{ fontSize: '16px', fontWeight: 600, color: 'var(--color-navy)', margin: '0 0 4px 0' }}>{doc.name || 'Unnamed Doctor'}</h3>
                                        <p style={{ fontSize: '13px', color: 'var(--color-text-secondary)', margin: 0 }}>{doc.specialization || (doc.role === 'doctor' ? 'Consultant' : doc.role) || 'Medical Staff'}</p>
                                    </div>
                                </div>
                                <span className={`badge ${doc.status === 'Active' ? 'badge-green' : 'badge-yellow'}`} style={{ padding: '4px 8px', fontSize: '11px' }}>{doc.status || 'Active'}</span>
                            </div>

                            <div style={{ flex: 1 }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px', fontSize: '13px' }}>
                                    <span style={{ color: 'var(--color-text-muted)' }}>Department:</span>
                                    <span style={{ fontWeight: 500, color: 'var(--color-text-primary)' }}>{doc.department || 'N/A'}</span>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px', fontSize: '13px' }}>
                                    <span style={{ color: 'var(--color-text-muted)' }}>Employee ID:</span>
                                    <span style={{ fontWeight: 500, fontFamily: 'monospace', color: 'var(--color-text-primary)' }}>{doc.userId || '—'}</span>
                                </div>
                            </div>

                            <div style={{ display: 'flex', gap: '8px', paddingTop: '16px', borderTop: '1px solid var(--color-border-light)' }}>
                                <button className="btn btn-secondary btn-sm" style={{ flex: 1, padding: '8px', background: '#F8FAFC', border: '1px solid transparent' }} title={doc.phone || 'No phone'}>
                                    <Phone size={14} color="var(--color-text-secondary)" />
                                </button>
                                <button className="btn btn-secondary btn-sm" style={{ flex: 1, padding: '8px', background: '#F8FAFC', border: '1px solid transparent' }} title={doc.email || 'No email'}>
                                    <Mail size={14} color="var(--color-text-secondary)" />
                                </button>
                                <button className="btn btn-secondary btn-sm" style={{ padding: '8px', background: '#F8FAFC', border: '1px solid transparent' }}>
                                    <MoreVertical size={14} color="var(--color-text-secondary)" />
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { Plus, Trash2, Edit2, Settings, Archive } from 'lucide-react';

export default function FacilitySettings() {
    const [wards, setWards] = useState([]);
    const [loading, setLoading] = useState(true);

    const [newWardName, setNewWardName] = useState('');
    const [newFloorWing, setNewFloorWing] = useState('');
    const [addingWard, setAddingWard] = useState(false);

    // Bed addition modal/form states
    const [activeWardId, setActiveWardId] = useState(null);
    const [bedPrefix, setBedPrefix] = useState('');
    const [bedStartNum, setBedStartNum] = useState(1);
    const [bedCount, setBedCount] = useState(5);
    const [addingBeds, setAddingBeds] = useState(false);

    useEffect(() => {
        fetchWards();
    }, []);

    const fetchWards = async () => {
        setLoading(true);
        try {
            const res = await fetch('/api/facility/wards');
            if (res.ok) {
                const data = await res.json();
                setWards(data.wards || []);
            }
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleAddWard = async (e) => {
        e.preventDefault();
        if (!newWardName.trim()) return;

        try {
            const res = await fetch('/api/facility/wards', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    name: newWardName,
                    floorWing: newFloorWing
                })
            });

            if (res.ok) {
                const data = await res.json();
                setWards([...wards, data.ward]);
                setNewWardName('');
                setNewFloorWing('');
                setAddingWard(false);
            } else {
                alert('Failed to add ward');
            }
        } catch (err) {
            console.error(err);
            alert('Error adding ward');
        }
    };

    const handleAddBeds = async (e) => {
        e.preventDefault();
        if (!activeWardId || !bedCount) return;

        try {
            const res = await fetch('/api/facility/beds', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    wardId: activeWardId,
                    prefix: bedPrefix,
                    startNumber: bedStartNum,
                    count: bedCount
                })
            });

            if (res.ok) {
                const data = await res.json();
                // Update local state with new beds
                setWards(wards.map(w => w.id === activeWardId ? { ...w, beds: data.beds } : w));
                setActiveWardId(null);
                setAddingBeds(false);
            } else {
                alert('Failed to add beds');
            }
        } catch (err) {
            console.error(err);
            alert('Error adding beds');
        }
    };

    const handleDeleteBed = async (wardId, bedId) => {
        if (!confirm('Are you sure you want to delete this bed?')) return;

        try {
            const res = await fetch(`/api/facility/beds?bedId=${bedId}`, {
                method: 'DELETE'
            });

            if (res.ok) {
                setWards(wards.map(w => {
                    if (w.id === wardId) {
                        return { ...w, beds: w.beds.filter(b => b.id !== bedId) };
                    }
                    return w;
                }));
            } else {
                alert('Failed to delete bed');
            }
        } catch (err) {
            console.error(err);
        }
    };

    if (loading) return <div style={{ padding: '40px', textAlign: 'center' }}>Loading facility data...</div>;

    return (
        <div className="fade-in">
            <div className="dashboard-header-row">
                <div>
                    <h1 className="page-header__title" style={{ marginBottom: '4px' }}>Facility Management</h1>
                    <p className="page-header__subtitle">Manage hospital wings, wards, and real bed inventory dynamically.</p>
                </div>
                <div className="dashboard-header-buttons">
                    <button className="btn btn-primary btn-sm" onClick={() => setAddingWard(true)}>
                        <Plus size={15} strokeWidth={1.5} />
                        Add New Ward
                    </button>
                </div>
            </div>

            {addingWard && (
                <div className="card" style={{ padding: '24px', marginBottom: '24px', background: '#FAFCFF', border: '1px solid #E2E8F0' }}>
                    <h3 style={{ fontSize: '16px', fontWeight: 600, color: 'var(--color-navy)', marginBottom: '16px' }}>Create New Ward / Wing</h3>
                    <form onSubmit={handleAddWard} style={{ display: 'flex', gap: '16px', alignItems: 'flex-end' }}>
                        <div style={{ flex: 1, display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
                            <div>
                                <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', color: 'var(--color-text-secondary)', fontWeight: 500 }}>Ward Name <span style={{ color: 'red' }}>*</span></label>
                                <input
                                    type="text"
                                    value={newWardName}
                                    onChange={e => setNewWardName(e.target.value)}
                                    style={{ width: '100%', padding: '10px 12px', border: '1px solid var(--color-border-light)', borderRadius: '8px', outline: 'none' }}
                                    placeholder="e.g. ICU, General Ward"
                                    required
                                />
                            </div>
                            <div>
                                <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', color: 'var(--color-text-secondary)', fontWeight: 500 }}>Floor / Wing (Optional)</label>
                                <input
                                    type="text"
                                    value={newFloorWing}
                                    onChange={e => setNewFloorWing(e.target.value)}
                                    style={{ width: '100%', padding: '10px 12px', border: '1px solid var(--color-border-light)', borderRadius: '8px', outline: 'none' }}
                                    placeholder="e.g. 2nd Floor, East Wing"
                                />
                            </div>
                        </div>
                        <div style={{ display: 'flex', gap: '12px' }}>
                            <button type="button" className="btn btn-secondary" onClick={() => setAddingWard(false)}>Cancel</button>
                            <button type="submit" className="btn btn-primary">Create Ward</button>
                        </div>
                    </form>
                </div>
            )}

            {addingBeds && activeWardId && (
                <div className="card" style={{ padding: '24px', marginBottom: '24px', background: '#F0FDF4', border: '1px solid #BBF7D0' }}>
                    <h3 style={{ fontSize: '16px', fontWeight: 600, color: '#166534', marginBottom: '16px' }}>
                        Generate Beds for {wards.find(w => w.id === activeWardId)?.name}
                    </h3>
                    <form onSubmit={handleAddBeds} style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '16px', alignItems: 'flex-end' }}>
                        <div>
                            <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', color: '#166534', fontWeight: 500 }}>Prefix (Optional)</label>
                            <input
                                type="text"
                                value={bedPrefix}
                                onChange={e => setBedPrefix(e.target.value)}
                                style={{ width: '100%', padding: '10px 12px', border: '1px solid #BBF7D0', borderRadius: '8px', outline: 'none' }}
                                placeholder="e.g. ICU"
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', color: '#166534', fontWeight: 500 }}>Starting Number</label>
                            <input
                                type="number"
                                value={bedStartNum}
                                onChange={e => setBedStartNum(e.target.value)}
                                style={{ width: '100%', padding: '10px 12px', border: '1px solid #BBF7D0', borderRadius: '8px', outline: 'none' }}
                                required
                            />
                        </div>
                        <div>
                            <label style={{ display: 'block', fontSize: '13px', marginBottom: '6px', color: '#166534', fontWeight: 500 }}>Number of Beds</label>
                            <input
                                type="number"
                                value={bedCount}
                                onChange={e => setBedCount(e.target.value)}
                                style={{ width: '100%', padding: '10px 12px', border: '1px solid #BBF7D0', borderRadius: '8px', outline: 'none' }}
                                min="1" max="50"
                                required
                            />
                        </div>
                        <div style={{ display: 'flex', gap: '8px' }}>
                            <button type="button" className="btn btn-secondary" style={{ flex: 1, background: '#fff', border: '1px solid #BBF7D0', color: '#166534' }} onClick={() => setAddingBeds(false)}>Cancel</button>
                            <button type="submit" className="btn btn-primary" style={{ flex: 1, background: '#16A34A' }}>Generate</button>
                        </div>
                    </form>
                </div>
            )}

            <div style={{ display: 'grid', gap: '24px' }}>
                {wards.length === 0 ? (
                    <div className="card" style={{ padding: '60px 20px', textAlign: 'center', color: 'var(--color-text-muted)' }}>
                        <Archive size={40} strokeWidth={1} style={{ margin: '0 auto 16px auto', opacity: 0.5 }} />
                        <h3>No Wards Configured</h3>
                        <p>Click "Add New Ward" to start building your hospital layout.</p>
                    </div>
                ) : (
                    wards.map(ward => (
                        <div key={ward.id} className="card" style={{ padding: '24px' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', paddingBottom: '16px', borderBottom: '1px solid var(--color-border-light)' }}>
                                <div>
                                    <h3 style={{ fontSize: '18px', fontWeight: 600, color: 'var(--color-navy)', margin: 0 }}>
                                        {ward.name}
                                        {ward.floorWing && <span style={{ fontSize: '13px', marginLeft: '12px', padding: '4px 8px', background: '#e2e8f0', borderRadius: '4px', color: '#475569', fontWeight: 500 }}>{ward.floorWing}</span>}
                                    </h3>
                                    <div style={{ fontSize: '13px', color: 'var(--color-text-secondary)', marginTop: '4px' }}>{ward.beds?.length || 0} Total Beds Configured</div>
                                </div>
                                <div style={{ display: 'flex', gap: '12px' }}>
                                    <button className="btn btn-secondary btn-sm" onClick={() => { setActiveWardId(ward.id); setAddingBeds(true); }}>
                                        <Plus size={14} /> Add Beds
                                    </button>
                                </div>
                            </div>

                            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(120px, 1fr))', gap: '12px' }}>
                                {(!ward.beds || ward.beds.length === 0) ? (
                                    <div style={{ gridColumn: '1 / -1', fontSize: '13px', color: 'var(--color-text-muted)', padding: '16px', background: '#F8FAFC', borderRadius: '8px', textAlign: 'center' }}>
                                        No beds populated in this ward yet.
                                    </div>
                                ) : (
                                    ward.beds.sort((a, b) => a.bedNumber.localeCompare(b.bedNumber, undefined, { numeric: true })).map(bed => (
                                        <div key={bed.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 14px', border: '1px solid var(--color-border-light)', borderRadius: '8px', background: '#FAFCFF' }}>
                                            <span style={{ fontSize: '14px', fontWeight: 600, color: 'var(--color-navy)', fontFamily: 'monospace' }}>{bed.bedNumber}</span>
                                            <button onClick={() => handleDeleteBed(ward.id, bed.id)} style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '4px', color: '#94A3B8' }} title="Delete Bed">
                                                <Trash2 size={14} />
                                            </button>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

'use client';
import { useState, useEffect } from 'react';
import { Settings, Shield, Bell, Database, Hospital, Mail, Building2, Save, CheckCircle, Loader2, Globe, IndianRupee } from 'lucide-react';

const TABS = [
    { label: 'Hospital Profile', icon: Hospital, key: 'profile' },
    { label: 'Billing & Currency', icon: IndianRupee, key: 'billing' },
    { label: 'Security & Access', icon: Shield, key: 'security' },
    { label: 'SMTP / Email', icon: Mail, key: 'smtp' },
    { label: 'Backup & Data', icon: Database, key: 'backup' },
];

const inputStyle = { width: '100%', padding: '11px 14px', border: '1px solid #E2E8F0', borderRadius: '8px', fontSize: '14px', outline: 'none', background: '#fff', fontFamily: 'inherit', boxSizing: 'border-box' };
const labelStyle = { display: 'block', fontSize: '13px', fontWeight: 600, color: '#334155', marginBottom: '7px' };
const hintStyle = { fontSize: '12px', color: '#94A3B8', margin: '0 0 8px' };

export default function SettingsPage() {
    const [activeTab, setActiveTab] = useState('profile');
    const [tenant, setTenant] = useState(null);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [saved, setSaved] = useState(false);
    const [error, setError] = useState('');

    const [form, setForm] = useState({
        name: '', phone: '', address: '', tagline: '', description: '',
        primaryColor: '#10B981', logoInitials: '', logoUrl: '', heroImage: '',
    });

    const f = (k) => (v) => setForm(prev => ({ ...prev, [k]: v.target ? v.target.value : v }));

    useEffect(() => {
        const load = async () => {
            setLoading(true);
            try {
                const res = await fetch('/api/settings');
                if (res.ok) {
                    const data = await res.json();
                    const t = data.tenant;
                    setTenant(t);
                    setForm({
                        name: t.name || '',
                        phone: t.phone || '',
                        address: t.address || '',
                        tagline: t.tagline || '',
                        description: t.description || '',
                        primaryColor: t.primaryColor || '#10B981',
                        logoInitials: t.logoInitials || '',
                        logoUrl: t.logoUrl || '',
                        heroImage: t.heroImage || '',
                    });
                }
            } catch (e) { setError('Failed to load settings.'); }
            finally { setLoading(false); }
        };
        load();
    }, []);

    const handleSave = async () => {
        setSaving(true); setSaved(false); setError('');
        try {
            const res = await fetch('/api/settings', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(form),
            });
            if (!res.ok) throw new Error((await res.json()).error || 'Save failed');
            setSaved(true);
            setTimeout(() => setSaved(false), 3000);
        } catch (e) { setError(e.message); }
        finally { setSaving(false); }
    };

    const SectionCard = ({ title, subtitle, children }) => (
        <div className="card" style={{ padding: 0, marginBottom: '24px' }}>
            <div style={{ padding: '20px 24px', borderBottom: '1px solid var(--color-border-light)' }}>
                <h2 style={{ fontSize: '16px', fontWeight: 700, color: 'var(--color-navy)', margin: 0 }}>{title}</h2>
                {subtitle && <p style={{ fontSize: '13px', color: 'var(--color-text-secondary)', margin: '4px 0 0 0' }}>{subtitle}</p>}
            </div>
            <div style={{ padding: '24px' }}>{children}</div>
        </div>
    );

    const Row = ({ children }) => (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px', marginBottom: '20px' }}>
            {children}
        </div>
    );

    return (
        <div className="fade-in">
            <div className="dashboard-header-row">
                <div>
                    <h1 className="page-header__title" style={{ marginBottom: '4px' }}>System Configuration</h1>
                    <p className="page-header__subtitle">Manage global hospital settings, preferences, billing rules, and integrations.</p>
                </div>
                <div className="dashboard-header-buttons">
                    <button className="btn btn-secondary btn-sm" style={{ background: '#fff' }} onClick={() => window.location.reload()}>Discard Changes</button>
                    <button className="btn btn-primary btn-sm" onClick={handleSave} disabled={saving || loading}>
                        {saving ? <Loader2 size={14} style={{ animation: 'spin 1s linear infinite' }} /> : saved ? <CheckCircle size={14} /> : <Save size={14} />}
                        {saving ? 'Saving…' : saved ? 'Saved!' : 'Save Configuration'}
                    </button>
                </div>
            </div>
            <style>{`@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}`}</style>

            {error && <div style={{ background: '#FEF2F2', border: '1px solid #FECACA', borderRadius: '10px', padding: '12px 16px', marginBottom: '20px', color: '#DC2626', fontSize: '14px' }}>{error}</div>}
            {saved && <div style={{ background: '#ECFDF5', border: '1px solid #A7F3D0', borderRadius: '10px', padding: '12px 16px', marginBottom: '20px', color: '#065F46', fontSize: '14px', display: 'flex', alignItems: 'center', gap: '8px' }}><CheckCircle size={16} /> Settings saved successfully!</div>}

            <div style={{ display: 'grid', gridTemplateColumns: '220px 1fr', gap: '24px', alignItems: 'start' }}>
                {/* Sidebar */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', position: 'sticky', top: '24px' }}>
                    {TABS.map(tab => (
                        <button key={tab.key} onClick={() => setActiveTab(tab.key)} style={{
                            display: 'flex', alignItems: 'center', gap: '12px', padding: '12px 16px',
                            borderRadius: '8px', border: 'none', cursor: 'pointer', textAlign: 'left',
                            fontWeight: activeTab === tab.key ? 600 : 500, fontSize: '14px', transition: 'all 0.15s',
                            color: activeTab === tab.key ? 'var(--color-cyan)' : 'var(--color-text-secondary)',
                            background: activeTab === tab.key ? 'rgba(0,194,255,0.1)' : 'transparent',
                        }}>
                            <tab.icon size={17} />
                            {tab.label}
                        </button>
                    ))}
                </div>

                {/* Content */}
                <div>
                    {loading ? (
                        <div style={{ padding: '60px', textAlign: 'center', color: '#94A3B8', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }}>
                            <Loader2 size={18} style={{ animation: 'spin 1s linear infinite' }} /> Loading settings…
                        </div>
                    ) : (
                        <>
                            {activeTab === 'profile' && (
                                <>
                                    <SectionCard title="Hospital Identity" subtitle="This information appears on invoices, reports, prescriptions, and your public website.">
                                        <Row>
                                            <div>
                                                <label style={labelStyle}>Hospital / Clinic Name</label>
                                                <input style={inputStyle} type="text" value={form.name} onChange={f('name')} placeholder="Apollo Health Systems" />
                                            </div>
                                            <div>
                                                <label style={labelStyle}>Primary Helpline Number</label>
                                                <input style={inputStyle} type="tel" value={form.phone} onChange={f('phone')} placeholder="+91 1800-000-0000" />
                                            </div>
                                        </Row>
                                        <Row>
                                            <div>
                                                <label style={labelStyle}>Tagline</label>
                                                <p style={hintStyle}>Shown as the hero headline on your public website</p>
                                                <input style={inputStyle} type="text" value={form.tagline} onChange={f('tagline')} placeholder="Your Health, Our Priority" />
                                            </div>
                                            <div>
                                                <label style={labelStyle}>Admin Email</label>
                                                <p style={hintStyle}>Read-only — contact support to change</p>
                                                <input style={{ ...inputStyle, background: '#F8FAFC', color: '#94A3B8' }} type="email" value={tenant?.adminEmail || ''} disabled />
                                            </div>
                                        </Row>
                                        <div style={{ marginBottom: '20px' }}>
                                            <label style={labelStyle}>Registered Address</label>
                                            <textarea rows={2} style={{ ...inputStyle, resize: 'vertical' }} value={form.address} onChange={f('address')} placeholder="123 Health Avenue, Medical District, Mumbai - 400001" />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>About Your Hospital</label>
                                            <p style={hintStyle}>2–3 sentences shown in the hero section and footer of your public website</p>
                                            <textarea rows={3} style={{ ...inputStyle, resize: 'vertical' }} value={form.description} onChange={f('description')} placeholder="Describe your hospital — specialities, experience, accreditations…" />
                                        </div>
                                    </SectionCard>

                                    <SectionCard title="Branding & Appearance" subtitle="Configure your brand color, logo initials, and image URLs for the public website.">
                                        <Row>
                                            <div>
                                                <label style={labelStyle}>Brand / Primary Color</label>
                                                <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                                                    <input type="color" value={form.primaryColor} onChange={f('primaryColor')} style={{ width: '48px', height: '44px', border: '1px solid #E2E8F0', borderRadius: '8px', cursor: 'pointer', padding: '3px' }} />
                                                    <input type="text" value={form.primaryColor} onChange={f('primaryColor')} style={{ ...inputStyle, fontFamily: 'monospace', letterSpacing: '0.04em' }} />
                                                </div>
                                            </div>
                                            <div>
                                                <label style={labelStyle}>Logo Initials (fallback)</label>
                                                <p style={hintStyle}>Used when no logo URL is set</p>
                                                <input type="text" maxLength={3} value={form.logoInitials} onChange={e => setForm(p => ({ ...p, logoInitials: e.target.value.toUpperCase() }))}
                                                    style={{ ...inputStyle, letterSpacing: '0.12em', fontWeight: 800, textTransform: 'uppercase', textAlign: 'center', fontSize: '16px' }} placeholder="NH" />
                                            </div>
                                        </Row>
                                        <Row>
                                            <div>
                                                <label style={labelStyle}>Logo Image URL</label>
                                                <p style={hintStyle}>Direct URL to PNG, SVG, or WebP</p>
                                                <input type="url" style={inputStyle} value={form.logoUrl} onChange={f('logoUrl')} placeholder="https://example.com/logo.png" />
                                            </div>
                                            <div>
                                                <label style={labelStyle}>Hero Background Image URL</label>
                                                <p style={hintStyle}>1920×1080 recommended. Uses gradient if empty.</p>
                                                <input type="url" style={inputStyle} value={form.heroImage} onChange={f('heroImage')} placeholder="https://example.com/hero.jpg" />
                                            </div>
                                        </Row>

                                        {/* Live preview strip */}
                                        <div style={{ background: '#F8FAFC', border: '1px solid #E2E8F0', borderRadius: '12px', padding: '16px 20px', display: 'flex', alignItems: 'center', gap: '16px' }}>
                                            <div style={{ width: '44px', height: '44px', borderRadius: '10px', background: `linear-gradient(135deg, ${form.primaryColor}, ${form.primaryColor}cc)`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                                                {form.logoUrl
                                                    ? <img src={form.logoUrl} alt="logo" style={{ height: '34px', maxWidth: '44px', objectFit: 'contain', borderRadius: '6px' }} onError={e => e.currentTarget.style.display = 'none'} />
                                                    : <span style={{ color: '#fff', fontWeight: 900, fontSize: '13px' }}>{form.logoInitials || form.name?.substring(0, 2).toUpperCase() || 'NH'}</span>}
                                            </div>
                                            <div>
                                                <div style={{ fontWeight: 700, color: 'var(--color-navy)', fontSize: '15px' }}>{form.name || 'Hospital Name'}</div>
                                                <div style={{ fontSize: '12px', color: '#94A3B8' }}>{form.tagline || 'Your Health, Our Priority'}</div>
                                            </div>
                                            <div style={{ marginLeft: 'auto', fontSize: '12px', color: '#94A3B8' }}>Live Preview</div>
                                        </div>
                                    </SectionCard>

                                    {/* Read-only plan info */}
                                    <SectionCard title="Subscription & Plan" subtitle="Managed by Nexora Health. Contact support to upgrade.">
                                        <Row>
                                            <div>
                                                <label style={labelStyle}>Current Plan</label>
                                                <input style={{ ...inputStyle, background: '#F8FAFC', color: '#94A3B8', fontWeight: 600 }} value={tenant?.plan || '—'} disabled />
                                            </div>
                                            <div>
                                                <label style={labelStyle}>Tenant Code</label>
                                                <input style={{ ...inputStyle, background: '#F8FAFC', color: '#94A3B8', fontFamily: 'monospace' }} value={tenant?.tenantCode || '—'} disabled />
                                            </div>
                                            <div>
                                                <label style={labelStyle}>Hospital Slug (URL)</label>
                                                <input style={{ ...inputStyle, background: '#F8FAFC', color: '#94A3B8', fontFamily: 'monospace' }} value={tenant?.slug ? `/${tenant.slug}` : '—'} disabled />
                                            </div>
                                            <div>
                                                <label style={labelStyle}>Account Status</label>
                                                <input style={{ ...inputStyle, background: '#F8FAFC', color: tenant?.status === 'Active' ? '#16A34A' : '#DC2626', fontWeight: 600 }} value={tenant?.status || '—'} disabled />
                                            </div>
                                        </Row>
                                    </SectionCard>
                                </>
                            )}

                            {activeTab === 'billing' && (
                                <SectionCard title="Billing & Currency" subtitle="Configure billing defaults, tax settings, and currency preferences.">
                                    <Row>
                                        <div>
                                            <label style={labelStyle}>Default Currency</label>
                                            <select style={{ ...inputStyle, cursor: 'pointer' }}>
                                                <option>INR (₹) Indian Rupee</option>
                                                <option>USD ($) US Dollar</option>
                                                <option>GBP (£) British Pound</option>
                                            </select>
                                        </div>
                                        <div>
                                            <label style={labelStyle}>GST / Tax Rate (%)</label>
                                            <input style={inputStyle} type="number" defaultValue="5" min="0" max="100" />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Default Payment Method</label>
                                            <select style={{ ...inputStyle, cursor: 'pointer' }}>
                                                <option>Cash</option>
                                                <option>UPI</option>
                                                <option>Credit Card</option>
                                                <option>TPA / Insurance</option>
                                            </select>
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Invoice Prefix</label>
                                            <input style={inputStyle} type="text" defaultValue="INV" placeholder="INV" />
                                        </div>
                                    </Row>
                                    <div style={{ background: '#EFF6FF', border: '1px solid #BFDBFE', borderRadius: '10px', padding: '14px 18px', fontSize: '13px', color: '#1E40AF' }}>
                                        ℹ️ Tax rate changes apply to new invoices only. Existing invoices are not retroactively updated.
                                    </div>
                                </SectionCard>
                            )}

                            {activeTab === 'security' && (
                                <SectionCard title="Security & Access Control" subtitle="Configure password policies, session timeout, and access restrictions.">
                                    <Row>
                                        <div>
                                            <label style={labelStyle}>Session Timeout (minutes)</label>
                                            <input style={inputStyle} type="number" defaultValue="60" min="5" />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>Minimum Password Length</label>
                                            <input style={inputStyle} type="number" defaultValue="8" min="6" />
                                        </div>
                                    </Row>
                                    <Row>
                                        {[
                                            { label: 'Require uppercase in passwords', defaultChecked: true },
                                            { label: 'Require special character in passwords', defaultChecked: true },
                                            { label: 'Enable two-factor authentication (2FA)', defaultChecked: false },
                                            { label: 'Lock account after 5 failed login attempts', defaultChecked: true },
                                        ].map(item => (
                                            <label key={item.label} style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer', fontSize: '14px', color: 'var(--color-text-primary)' }}>
                                                <input type="checkbox" defaultChecked={item.defaultChecked} style={{ width: '16px', height: '16px', accentColor: 'var(--color-cyan)' }} />
                                                {item.label}
                                            </label>
                                        ))}
                                    </Row>
                                </SectionCard>
                            )}

                            {activeTab === 'smtp' && (
                                <SectionCard title="SMTP / Email Configuration" subtitle="Configure outbound email for reports, notifications, and receipts.">
                                    <Row>
                                        <div>
                                            <label style={labelStyle}>SMTP Host</label>
                                            <input style={inputStyle} type="text" placeholder="smtp.gmail.com" />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>SMTP Port</label>
                                            <input style={inputStyle} type="number" placeholder="587" />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>SMTP Username / Email</label>
                                            <input style={inputStyle} type="email" placeholder="notifications@yourhospital.com" />
                                        </div>
                                        <div>
                                            <label style={labelStyle}>SMTP Password</label>
                                            <input style={inputStyle} type="password" placeholder="App password or SMTP key" />
                                        </div>
                                    </Row>
                                    <div style={{ background: '#FFFBEB', border: '1px solid #FDE68A', borderRadius: '10px', padding: '14px 18px', fontSize: '13px', color: '#92400E' }}>
                                        ⚠️ Use app-specific passwords with Gmail. Never use your main Google account password here.
                                    </div>
                                </SectionCard>
                            )}

                            {activeTab === 'backup' && (
                                <SectionCard title="Backup & Data Management" subtitle="Export your hospital data or restore from a previous backup.">
                                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px', marginBottom: '24px' }}>
                                        {[
                                            { label: 'Export Patient Records', desc: 'All patient data as CSV', icon: '📋' },
                                            { label: 'Export Appointment History', desc: 'All appointments as CSV', icon: '📅' },
                                            { label: 'Export Pharmacy Inventory', desc: 'Medicine stock as CSV', icon: '💊' },
                                            { label: 'Export Billing Records', desc: 'All invoices as CSV', icon: '🧾' },
                                        ].map(item => (
                                            <div key={item.label} style={{ border: '1px solid #E2E8F0', borderRadius: '12px', padding: '18px', display: 'flex', alignItems: 'center', gap: '14px', cursor: 'pointer', transition: 'all 0.15s' }}
                                                onMouseOver={e => { e.currentTarget.style.borderColor = 'var(--color-cyan)'; e.currentTarget.style.background = '#F0FDFF'; }}
                                                onMouseOut={e => { e.currentTarget.style.borderColor = '#E2E8F0'; e.currentTarget.style.background = '#fff'; }}>
                                                <div style={{ fontSize: '24px' }}>{item.icon}</div>
                                                <div>
                                                    <div style={{ fontWeight: 600, fontSize: '14px', color: 'var(--color-navy)' }}>{item.label}</div>
                                                    <div style={{ fontSize: '12px', color: '#94A3B8' }}>{item.desc}</div>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                    <div style={{ background: '#FEF2F2', border: '1px solid #FECACA', borderRadius: '10px', padding: '14px 18px', fontSize: '13px', color: '#991B1B' }}>
                                        🔴 Data deletion is irreversible. Contact Nexora Health support before performing any destructive operations.
                                    </div>
                                </SectionCard>
                            )}
                        </>
                    )}
                </div>
            </div>
        </div>
    );
}

